ALTER TABLE technologies DROP COLUMN subcategory_id;
ALTER TABLE technologies DROP COLUMN class_type_id;
ALTER TABLE technologies DROP COLUMN patch_compliance;
ALTER TABLE technologies DROP COLUMN asset_status;
